/*
  # ENEM: nova tabela enem_resultados + carga (ENEM 2024, rotulado 2025)

  Fonte: planilha "ENEM - Escolas Parana.xlsx" (abas por cidade). Cada escola tem
  posicao_geral (rank estadual), posicao (rank na cidade), medias por area
  (LC=Linguagens, CH=Ciencias Humanas, CN=Ciencias da Natureza, MT=Matematica,
  RD=Redacao) e media geral (media das 5 areas). `is_apogeu` marca as 15 escolas
  do grupo Apogeu (identificadas pela posicao na cidade). `regional` fica NULL ate
  o mapa cidade->regional ser informado.
*/
CREATE TABLE IF NOT EXISTS enem_resultados (
  id uuid PRIMARY KEY DEFAULT gen_random_uuid(),
  ano text NOT NULL DEFAULT '2025',
  edicao_enem text,
  posicao_geral integer,
  posicao integer,
  escola text NOT NULL,
  inep_codigo text,
  cidade text NOT NULL,
  regional text,
  dependencia text,
  localizacao text,
  alunos integer NOT NULL DEFAULT 0,
  lc numeric, ch numeric, cn numeric, mt numeric, rd numeric, media numeric,
  is_apogeu boolean NOT NULL DEFAULT false,
  created_at timestamptz DEFAULT now()
);

ALTER TABLE enem_resultados ENABLE ROW LEVEL SECURITY;
DROP POLICY IF EXISTS "enem_all_public" ON enem_resultados;
CREATE POLICY "enem_all_public" ON enem_resultados FOR ALL TO public USING (true) WITH CHECK (true);

CREATE INDEX IF NOT EXISTS idx_enem_ano ON enem_resultados(ano);
CREATE INDEX IF NOT EXISTS idx_enem_apogeu ON enem_resultados(is_apogeu);
CREATE INDEX IF NOT EXISTS idx_enem_cidade ON enem_resultados(cidade);

-- Carga idempotente: limpa e recarrega os 267 registros da planilha.
DELETE FROM enem_resultados WHERE ano = '2025';

