-- Regional (mapa cidade->regional derivado das escolas do grupo Apogeu, enviado pelo usuario:
-- CWT=Curitiba, SJP=Sao Jose dos Pinhais, GUA=Guarapuava). Cada cidade mapeia para 1 regional.
UPDATE enem_resultados SET regional = CASE cidade
  WHEN 'Curitiba'             THEN 'CWT'
  WHEN 'Fazenda Rio Grande'   THEN 'CWT'
  WHEN 'São José dos Pinhais' THEN 'SJP'
  WHEN 'Guarapuava'           THEN 'GUA'
  WHEN 'Cornélio Procópio'    THEN 'GUA'
  WHEN 'Roncador'             THEN 'GUA'
END
WHERE ano = '2025';
